func tokenCost(line string) bool {
	lower := strings.ToLower(line)
	if containsAny(lower, []string{
		"very important",
		"in order to",
		"effectively",
		"begin to",
		"make the experience better",
	}) {
		return true
	}
	return countMatches(lower, []string{"robust", "comprehensive", "smooth", "elegant", "excited", "high"}) >= 2
}

