	if !containsAllStrings(settings.Vocabulary.Accept, []string{"DDx", "bead", "execution", "Helix", "Fizeau"}) {
		t.Fatalf("default accept vocabulary missing DDx terms: %+v", settings.Vocabulary.Accept)
	}
}

